CREATE TABLE wind_farms (id INT, country VARCHAR(255), energy_generated FLOAT); INSERT INTO wind_farms (id, country, energy_generated) VALUES (1, 'Germany', 1234.56), (2, 'France', 6543.21), (3, 'Spain', 4321.09), (4, 'Germany', 1345.67), (5, 'France', 7654.32), (6, 'Spain', 5432.10);
Q: What is the average energy generated by wind farms in Germany, France, and Spain?
A: SELECT AVG(energy_generated) FROM wind_farms WHERE country IN ('Germany', 'France', 'Spain');

CREATE TABLE Materials(id INT, material_name VARCHAR(50), quantity INT, usage_date DATE, is_sustainable BOOLEAN); INSERT INTO Materials(id, material_name, quantity, usage_date, is_sustainable) VALUES (1, 'Organic Cotton', 500, '2022-01-01', true); INSERT INTO Materials(id, material_name, quantity, usage_date, is_sustainable) VALUES (2, 'Recycled Polyester', 300, '2022-01-15', true);
Q: Find the total quantity of sustainable materials used in the last 6 months in the UK.
A: SELECT SUM(quantity) FROM Materials WHERE is_sustainable = true AND usage_date >= DATEADD(month, -6, GETDATE()) AND usage_country = 'UK';

CREATE TABLE ethical_products_report (product_id INT, product_name VARCHAR(50), price DECIMAL, ethical BOOLEAN); CREATE TABLE inventory (product_id INT, in_stock INT); INSERT INTO ethical_products_report (product_id, product_name, price, ethical) VALUES (1, 'Product A', 15.99, true), (2, 'Product B', 25.49, false), (3, 'Product C', 12.99, true); INSERT INTO inventory (product_id, in_stock) VALUES (1, 50), (3, 100), (6, 75);
Q: Find all products that are not present in the ethical products report but are in the inventory.
A: SELECT i.product_id, e.product_name, i.in_stock FROM inventory i LEFT JOIN ethical_products_report e ON i.product_id = e.product_id WHERE e.product_id IS NULL;

CREATE TABLE ethical_ai (id INT, industry VARCHAR(20), budget INT); INSERT INTO ethical_ai (id, industry, budget) VALUES (1, 'technology', 10000), (2, 'finance', 12000), (3, 'healthcare', 15000);
Q: What is the minimum budget allocated for ethical AI projects in the technology industry?
A: SELECT MIN(budget) FROM ethical_ai WHERE industry = 'technology';

CREATE TABLE MinimumWages (factory VARCHAR(255), country VARCHAR(255), wage DECIMAL(10,2)); INSERT INTO MinimumWages (factory, country, wage) VALUES ('FairTradeFactoryC', 'Pakistan', 4.0);
Q: What is the minimum wage in fair trade factories in Pakistan?
A: SELECT MIN(wage) FROM MinimumWages WHERE factory LIKE '%Fair Trade%' AND country = 'Pakistan';

CREATE TABLE policy (policy_number INT, coverage_amount INT, policyholder_age INT); INSERT INTO policy VALUES (1, 50000, 70); INSERT INTO policy VALUES (2, 75000, 30);
Q: What is the average coverage amount for policies with a policyholder age greater than or equal to 65?
A: SELECT AVG(coverage_amount) FROM policy WHERE policyholder_age >= 65;

CREATE TABLE Sales (sale_id INT, menu_id INT, sale_date DATE, quantity INT, price DECIMAL(5,2)); INSERT INTO Sales (sale_id, menu_id, sale_date, quantity, price) VALUES (1, 1, '2022-01-01', 2, 5.99), (2, 2, '2022-01-02', 1, 7.99), (3, 3, '2022-01-03', 3, 4.99), (4, 4, '2022-01-04', 4, 6.99); CREATE TABLE Menus (menu_id INT, category VARCHAR(255), dish_name VARCHAR(255), price DECIMAL(5,2)); INSERT INTO Menus (menu_id, category, dish_name, price) VALUES (1, 'Appetizer', 'Bruschetta', 5.99), (2, 'Entree', 'Spaghetti', 7.99), (3, 'Appetizer', 'Calamari', 4.99), (4, 'Appetizer', 'Nachos', 6.99);
Q: What is the total revenue generated from dishes in the 'Appetizer' category?
A: SELECT SUM(quantity * price) FROM Sales JOIN Menus ON Sales.menu_id = Menus.menu_id WHERE Menus.category = 'Appetizer';

CREATE TABLE Veteran_Employment (id INT, state VARCHAR(50), unemployment_rate FLOAT); INSERT INTO Veteran_Employment (id, state, unemployment_rate) VALUES (1, 'California', 3.5), (2, 'Texas', 4.0);
Q: Show veteran unemployment rates by state?
A: SELECT Veteran_Employment.state, Veteran_Employment.unemployment_rate FROM Veteran_Employment ORDER BY Veteran_Employment.unemployment_rate;

CREATE TABLE developers (id INT, name VARCHAR(50), salary FLOAT, project VARCHAR(50));
Q: Insert a new record for a developer who works on a technology accessibility project
A: INSERT INTO developers (id, name, salary, project) VALUES (3, 'Charlie', 90000.0, 'Technology Accessibility');

CREATE TABLE carbon_sequestration (id INT PRIMARY KEY, ecosystem TEXT, region TEXT, sequestration_rate FLOAT); INSERT INTO carbon_sequestration (id, ecosystem, region, sequestration_rate) VALUES (1, 'Temperate Rainforest', 'North America', 28);
Q: Update the carbon_sequestration table to set the sequestration_rate to 30 tons/hectare for 'Temperate Rainforest' in 'North America'
A: UPDATE carbon_sequestration SET sequestration_rate = 30 WHERE ecosystem = 'Temperate Rainforest' AND region = 'North America';

CREATE TABLE WorkoutTypes (Id INT PRIMARY KEY, WorkoutType VARCHAR(50));
Q: Update the name of the workout type "Cardio Kickboxing" to "Kickboxing Cardio" in the "WorkoutTypes" table
A: UPDATE WorkoutTypes SET WorkoutType = 'Kickboxing Cardio' WHERE WorkoutType = 'Cardio Kickboxing';

CREATE TABLE factories (factory_id INT, location VARCHAR(50), capacity INT); INSERT INTO factories (factory_id, location, capacity) VALUES (1, 'Madrid, Spain', 5000), (2, 'Paris, France', 7000), (3, 'London, UK', 6000);
Q: What is the total capacity of factories in Spain and France?
A: SELECT SUM(capacity) FROM factories WHERE location LIKE '%Spain%' OR location LIKE '%France%';

CREATE TABLE vulnerabilities (id INT, name VARCHAR(255), severity VARCHAR(50), description TEXT, affected_products TEXT, date_discovered DATE);
Q: What is the total number of vulnerabilities in the 'vulnerabilities' table?
A: SELECT COUNT(*) FROM vulnerabilities;

CREATE TABLE city_complaints (city varchar(50), year int, category varchar(50), num_complaints int); INSERT INTO city_complaints (city, year, category, num_complaints) VALUES ('Chicago', 2021, 'Public Transportation', 3500);
Q: How many citizen complaints were received by the city of Chicago regarding public transportation in 2021?
A: SELECT SUM(num_complaints) FROM city_complaints WHERE city = 'Chicago' AND category = 'Public Transportation' AND year = 2021;

CREATE TABLE drought_impact (region VARCHAR(20), state VARCHAR(20), population INT); INSERT INTO drought_impact (region, state, population) VALUES ('Central Valley', 'California', 600000), ('Los Angeles', 'California', 4000000), ('San Diego', 'California', 1500000);
Q: Which drought-impacted regions in the state of California have a population greater than 500,000?
A: SELECT region FROM drought_impact WHERE state = 'California' AND population > 500000;

CREATE TABLE TrainingSessions (SessionID INT, SessionName VARCHAR(50), SessionDate DATE, NumberOfAttendees INT);
Q: What is the total number of diversity and inclusion training sessions conducted in the last quarter?
A: SELECT COUNT(*) as TotalSessions FROM TrainingSessions WHERE SessionName = 'Diversity and Inclusion' AND SessionDate >= DATE_SUB(CURDATE(), INTERVAL 3 MONTH);

CREATE TABLE Organizations (OrgID INT, OrgName TEXT); CREATE TABLE Volunteers (VolID INT, OrgID INT, VolunteerHours INT); INSERT INTO Organizations (OrgID, OrgName) VALUES (1, 'Habitat for Humanity'), (2, 'American Red Cross'); INSERT INTO Volunteers (VolID, OrgID, VolunteerHours) VALUES (1, 1, 100), (2, 1, 200), (3, 2, 300), (4, 2, 400);
Q: What is the total number of volunteers for each organization?
A: SELECT OrgName, SUM(VolunteerHours) FROM Volunteers JOIN Organizations ON Volunteers.OrgID = Organizations.OrgID GROUP BY OrgName;

CREATE TABLE GraduateStudentPublications(StudentID INT, PublicationDate DATE); INSERT INTO GraduateStudentPublications (StudentID, PublicationDate) VALUES (1, '2021-01-01'), (2, '2020-01-01');
Q: List the graduate students who have not published any research in the past year.
A: SELECT g.StudentID, g.Name FROM GraduateStudents g LEFT JOIN GraduateStudentPublications p ON g.StudentID = p.StudentID WHERE p.PublicationDate IS NULL AND YEAR(p.PublicationDate) = YEAR(CURRENT_DATE()) - 1;

CREATE TABLE drugs (drug_id INT, drug_name TEXT, sales_figure INT, region TEXT); INSERT INTO drugs (drug_id, drug_name, sales_figure, region) VALUES (1, 'DrugA', 500, 'Asia-Pacific'), (2, 'DrugB', 750, 'Europe');
Q: What are the total sales figures for each drug in the 'drugs' table, including drugs with no sales, in the Asia-Pacific region?
A: SELECT d.drug_name, COALESCE(SUM(s.sales_figure), 0) AS total_sales FROM drugs d LEFT JOIN sales s ON d.drug_id = s.drug_id WHERE d.region = 'Asia-Pacific' GROUP BY d.drug_name;

CREATE TABLE health_equity_metrics (id INT, name TEXT, score INT, category TEXT);
Q: What is the average cultural competency score of health equity metrics?
A: SELECT AVG(score) FROM health_equity_metrics WHERE category = 'cultural competency';

CREATE TABLE CompanyFunding(id INT, name TEXT, founding_year INT, funding_amount INT, racial_ethnicity TEXT);   INSERT INTO CompanyFunding VALUES (1, 'TechCo', 2016, 6000000, 'Latinx'), (2, 'GreenTech', 2014, 8000000, 'Caucasian'), (3, 'AIStudio', 2021, 4000000, 'African'), (4, 'RenewableEnergy', 2018, 9000000, 'Latinx'), (5, 'CloudServices', 2020, 5000000, 'Asian'), (6, 'SmartCity', 2017, 7000000, 'Latinx'), (7, 'DataAnalytics', 2019, 3000000, 'Latinx');
Q: What is the average funding amount for companies founded by Latinx entrepreneurs in the last 7 years?
A: SELECT AVG(funding_amount) FROM CompanyFunding WHERE racial_ethnicity = 'Latinx' AND founding_year >= YEAR(CURRENT_DATE) - 7;

CREATE TABLE readers (id INT, age INT, gender VARCHAR(10), country VARCHAR(50), news_preference VARCHAR(50)); INSERT INTO readers (id, age, gender, country, news_preference) VALUES (1, 50, 'Male', 'Australia', 'Political'), (2, 30, 'Female', 'Australia', 'Political');
Q: Find the difference between the maximum and minimum age of readers who prefer political news in Australia.
A: SELECT MAX(age) - MIN(age) diff FROM readers WHERE country = 'Australia' AND news_preference = 'Political';

CREATE TABLE ethical_practices (employee_id INT, department TEXT, is_ethical BOOLEAN); CREATE TABLE employees (employee_id INT, employee_name TEXT);
Q: What is the total number of employees, and how many of them work in departments that have ethical practices?
A: SELECT COUNT(DISTINCT ethical_practices.employee_id) AS total_employees, SUM(ethical_practices.is_ethical) AS ethical_employees FROM ethical_practices INNER JOIN employees ON ethical_practices.employee_id = employees.employee_id;

CREATE TABLE startups (id INT, name VARCHAR(255), location VARCHAR(255), budget FLOAT); INSERT INTO startups (id, name, location, budget) VALUES (1, 'StartupA', 'USA', 5000000); INSERT INTO startups (id, name, location, budget) VALUES (2, 'StartupB', 'USA', 7000000);
Q: What is the average budget allocated for bioprocess engineering R&D in startups located in the United States?
A: SELECT AVG(budget) FROM startups WHERE location = 'USA' AND category = 'bioprocess engineering';

CREATE TABLE workforce_training (id INT PRIMARY KEY, employee_name VARCHAR(255), training_topic VARCHAR(255), training_hours INT, training_completion_date DATE);
Q: Create a table named 'workforce_training'
A: CREATE TABLE workforce_training (id INT PRIMARY KEY, employee_name VARCHAR(255), training_topic VARCHAR(255), training_hours INT, training_completion_date DATE);

CREATE TABLE space_missions (id INT, name VARCHAR(255), mission_type VARCHAR(255), country VARCHAR(255), start_date DATE, end_date DATE); INSERT INTO space_missions (id, name, mission_type, country, start_date, end_date) VALUES (1, 'Apollo 11', 'Human', 'USA', '1969-07-16', '1969-07-24'); INSERT INTO space_missions (id, name, mission_type, country, start_date, end_date) VALUES (2, 'Mars Science Laboratory', 'Robotic', 'USA', '2011-11-26', '2012-08-06'); INSERT INTO space_missions (id, name, mission_type, country, start_date, end_date) VALUES (3, 'Mars Orbiter Mission', 'Robotic', 'India', '2013-11-05', NULL);
Q: What are the names and countries of the Mars missions that have not yet ended?
A: SELECT name, country FROM space_missions WHERE end_date IS NULL;

CREATE TABLE Patients (PatientID INT, Age INT, Gender VARCHAR(10), Rural BOOLEAN, Disease VARCHAR(20)); INSERT INTO Patients (PatientID, Age, Gender, Rural, Disease) VALUES (1, 34, 'Male', TRUE, 'Diabetes'), (2, 55, 'Female', FALSE, 'Diabetes');
Q: What is the average age of rural male patients with diabetes?
A: SELECT AVG(Age) FROM Patients WHERE Rural = TRUE AND Gender = 'Male' AND Disease = 'Diabetes';

CREATE TABLE creative_ai_applications_training_times (id INT, application VARCHAR(25), training_time FLOAT); INSERT INTO creative_ai_applications_training_times (id, application, training_time) VALUES (1, 'Art Generation', 2.5), (2, 'Music Composition', 3.2), (3, 'Text Generation', 2.8), (4, 'Image Recognition', 1.5), (5, 'Speech Recognition', 4.2);
Q: What is the average training time for creative AI applications?
A: SELECT AVG(training_time) as avg_training_time FROM creative_ai_applications_training_times;

CREATE TABLE mangroves (id INT, name TEXT, area_size FLOAT, location TEXT); INSERT INTO mangroves (id, name, area_size, location) VALUES (1, 'Bonaire Mangroves', 1200, 'Caribbean');
Q: What is the total area covered by mangroves in the Caribbean?"
A: SELECT SUM(area_size) FROM mangroves WHERE location = 'Caribbean';

CREATE TABLE imports (import_id INT, import_date DATE, weight INT, country TEXT, product TEXT); INSERT INTO imports (import_id, import_date, weight, country, product) VALUES (1, '2022-01-01', 500, 'Germany', 'Frozen Fish'), (2, '2022-01-05', 600, 'France', 'Frozen Chicken'), (3, '2022-02-10', 700, 'India', 'Fish'), (4, '2022-03-15', 800, 'England', 'Frozen Vegetables');
Q: Determine the total weight of all 'Frozen' products imported from 'Europe'
A: SELECT SUM(weight) FROM imports WHERE product LIKE 'Frozen%' AND country IN ('Germany', 'France', 'England');

CREATE TABLE co_ownership_diversity (id INT, owner VARCHAR(20), shared_cost INT); INSERT INTO co_ownership_diversity (id, owner, shared_cost) VALUES (1, 'Jamal', 55000), (2, 'Leila', 48000), (3, 'Steve', 62000);
Q: What is the minimum 'shared_cost' in the 'co_ownership_diversity' table?
A: SELECT MIN(shared_cost) FROM co_ownership_diversity;

CREATE TABLE GraduateStudents(StudentID INT, Name VARCHAR(50), Department VARCHAR(50)); INSERT INTO GraduateStudents VALUES (1, 'James Johnson', 'Physics'); INSERT INTO GraduateStudents VALUES (2, 'Sophia Williams', 'Mathematics'); CREATE TABLE Publications(PublicationID INT, StudentID INT, Journal VARCHAR(50)); INSERT INTO Publications VALUES (1, 1, 'Journal of Physics');
Q: List the graduate students who have not yet published any articles in academic journals.
A: SELECT GS.Name FROM GraduateStudents GS LEFT JOIN Publications P ON GS.StudentID = P.StudentID WHERE P.PublicationID IS NULL;

CREATE TABLE humanitarian_assistance (assistance_id INT PRIMARY KEY, assistance_type VARCHAR(50), country VARCHAR(50), year INT);
Q: Insert new records for 'Peaceful Aid' in 'Haiti' during 2010 and 'Emergency Assistance' in 'Pakistan' during 2005 to the "humanitarian_assistance" table
A: INSERT INTO humanitarian_assistance (assistance_id, assistance_type, country, year) VALUES (1, 'Peaceful Aid', 'Haiti', 2010), (2, 'Emergency Assistance', 'Pakistan', 2005);

CREATE TABLE Green_Buildings (id INT, region VARCHAR(20), number_of_buildings INT); INSERT INTO Green_Buildings (id, region, number_of_buildings) VALUES (1, 'Europe', 5000), (2, 'Asia', 7000), (3, 'Africa', 3000);
Q: What is the total number of green buildings in Asia?
A: SELECT SUM(number_of_buildings) FROM Green_Buildings WHERE region = 'Asia';

CREATE TABLE energy_efficiency_improvement (province VARCHAR(20), improvement DECIMAL(4,2), year INT); INSERT INTO energy_efficiency_improvement (province, improvement, year) VALUES ('British Columbia', 3.4, 2022), ('British Columbia', 3.8, 2022), ('British Columbia', 4.1, 2022);
Q: What is the maximum energy efficiency improvement for the province of British Columbia in 2022?
A: SELECT MAX(improvement) FROM energy_efficiency_improvement WHERE province = 'British Columbia' AND year = 2022;

CREATE SCHEMA if not exists arts_culture;CREATE TABLE if not exists arts_culture.audiences (audience_id INT PRIMARY KEY, name VARCHAR(255));CREATE TABLE if not exists arts_culture.events (event_id INT PRIMARY KEY, name VARCHAR(255), audience_id INT, FOREIGN KEY (audience_id) REFERENCES arts_culture.audiences(audience_id));INSERT INTO arts_culture.audiences (audience_id, name) VALUES (1, 'John Doe'), (2, 'Jane Smith'), (3, 'Jim Brown');INSERT INTO arts_culture.events (event_id, name, audience_id) VALUES (1, 'Art Exhibition', 1), (2, 'Theater Performance', 1), (3, 'Music Concert', 2);
Q: How many events have been attended by each audience member?
A: SELECT a.name as audience_name, COUNT(e.event_id) as attended_events FROM arts_culture.audiences a JOIN arts_culture.events e ON a.audience_id = e.audience_id GROUP BY a.name;

CREATE TABLE pesticide_applications (application_date DATE, farm_id INT, crop TEXT); INSERT INTO pesticide_applications (application_date, farm_id, crop) VALUES ('2021-07-01', 301, 'Cotton'), ('2021-07-02', 302, 'Cotton'), ('2020-04-01', 303, 'Cotton');
Q: What is the total number of pesticide-treated cotton farms in Australia in the past year?
A: SELECT COUNT(DISTINCT farm_id) FROM pesticide_applications WHERE crop = 'Cotton' AND application_date > DATE_SUB(CURDATE(), INTERVAL 1 YEAR);

CREATE TABLE flights_brazil (id INT, type VARCHAR(50), country VARCHAR(50), co2_emission DECIMAL(5,2), flight_year INT); INSERT INTO flights_brazil (id, type, country, co2_emission, flight_year) VALUES (1, 'Domestic', 'Brazil', 120.5, 2019), (2, 'International', 'Brazil', 250.3, 2019), (3, 'Domestic', 'Brazil', 150.7, 2019), (4, 'Domestic', 'Brazil', 135.2, 2020), (5, 'Domestic', 'Brazil', 148.9, 2021);
Q: What is the average CO2 emission for domestic flights in Brazil between 2019 and 2021?
A: SELECT AVG(co2_emission) FROM flights_brazil WHERE type = 'Domestic' AND country = 'Brazil' AND flight_year BETWEEN 2019 AND 2021;

CREATE TABLE program (id INT, name VARCHAR(255)); CREATE TABLE student (id INT, program_id INT, enrollment_date DATE);
Q: What is the average number of students in each graduate program?
A: SELECT program.name, AVG(DATEDIFF(CURDATE(), student.enrollment_date) / 365) FROM program LEFT JOIN student ON program.id = student.program_id GROUP BY program.name;

CREATE TABLE small_scale_farmers (id INT, country VARCHAR(20), initiative_id INT); CREATE TABLE food_justice_initiatives (id INT, name VARCHAR(50)); INSERT INTO small_scale_farmers (id, country, initiative_id) VALUES (1, 'BR', 101), (2, 'ZA', 102), (3, 'BR', 103), (4, 'ZA', 104); INSERT INTO food_justice_initiatives (id, name) VALUES (101, 'Sempreviva'), (102, 'Food Sovereignty South Africa'), (103, 'Articulação Nacional de Agroecologia'), (104, 'Sustainability Institute');
Q: How many small-scale farmers in Brazil and South Africa are part of food justice initiatives?
A: SELECT COUNT(DISTINCT small_scale_farmers.id) FROM small_scale_farmers INNER JOIN food_justice_initiatives ON small_scale_farmers.initiative_id = food_justice_initiatives.id WHERE small_scale_farmers.country IN ('BR', 'ZA');

CREATE TABLE sustainable_material_brands (brand_id INT PRIMARY KEY, brand_name VARCHAR(100), added_date DATE);
Q: How many sustainable material brands were added in the past year?
A: SELECT COUNT(*) FROM sustainable_material_brands WHERE added_date >= DATE_SUB(NOW(), INTERVAL 1 YEAR);

CREATE TABLE Donations (id INT, donor_id INT, country VARCHAR(20), artworks_donated INT); INSERT INTO Donations (id, donor_id, country, artworks_donated) VALUES (1, 1, 'India', 25), (2, 2, 'USA', 30), (3, 3, 'India', 45);
Q: What is the total number of artworks donated by artists from India?
A: SELECT SUM(artworks_donated) FROM Donations WHERE country = 'India';

CREATE TABLE hospitals (id INT PRIMARY KEY, name VARCHAR(255), beds INT, location VARCHAR(255)); INSERT INTO hospitals (id, name, beds, location) VALUES (1, 'Johns Hopkins Hospital', 1138, 'Baltimore, MD'); INSERT INTO hospitals (id, name, beds, location) VALUES (2, 'Massachusetts General Hospital', 999, 'Boston, MA'); INSERT INTO hospitals (id, name, beds, location) VALUES (3, 'University of California Medical Center', 500, 'Los Angeles, CA');
Q: What is the total number of hospital beds in hospitals located in California?
A: SELECT SUM(beds) FROM hospitals WHERE location LIKE '%California%';

CREATE TABLE supplier_items (id INT, supplier_id INT, item_id INT, price DECIMAL(5,2)); INSERT INTO supplier_items (id, supplier_id, item_id, price) VALUES (1, 1, 1, 50.99), (2, 1, 2, 45.99), (3, 2, 3, 39.99); CREATE TABLE suppliers (id INT, name VARCHAR(50), country VARCHAR(50)); INSERT INTO suppliers (id, name, country) VALUES (1, 'Green Trade', 'India'), (2, 'EcoFriendly Co.', 'China'), (3, 'Sustainable Source', 'Brazil');
Q: Who are the top 3 most expensive suppliers?
A: SELECT suppliers.name, MAX(supplier_items.price) AS max_price FROM supplier_items INNER JOIN suppliers ON supplier_items.supplier_id = suppliers.id GROUP BY suppliers.id ORDER BY max_price DESC LIMIT 3;

CREATE TABLE Products (productID int, productName varchar(255), circularSupplyChain varchar(5)); INSERT INTO Products VALUES (1, 'ProductA', 'Y'); CREATE TABLE Sales (saleID int, productID int, quantity int, date datetime); INSERT INTO Sales VALUES (1, 1, 50, '2021-01-01');
Q: Find the top 5 most sold products in the circular supply chain in 2021.
A: SELECT P.productName, SUM(S.quantity) as total_sold FROM Products P INNER JOIN Sales S ON P.productID = S.productID WHERE P.circularSupplyChain = 'Y' AND YEAR(S.date) = 2021 GROUP BY P.productID ORDER BY total_sold DESC LIMIT 5;

CREATE TABLE AircraftModels (model_id INT, name VARCHAR(50), manufacturer VARCHAR(50), country VARCHAR(50)); INSERT INTO AircraftModels (model_id, name, manufacturer, country) VALUES (1, 'Air1', 'AvionicCorp', 'USA'), (2, 'Air2', 'AvionicCorp', 'Canada');
Q: Which aircraft models were manufactured by AvionicCorp in the US?
A: SELECT name FROM AircraftModels WHERE manufacturer = 'AvionicCorp' AND country = 'USA';

CREATE TABLE wind_farms (id INT, country VARCHAR(255), name VARCHAR(255), capacity FLOAT); INSERT INTO wind_farms (id, country, name, capacity) VALUES (1, 'Germany', 'Windfarm A', 50.5), (2, 'Spain', 'Windfarm B', 60.3);
Q: What is the total installed capacity of wind farms in Germany and Spain, and how many projects does this sum represent?
A: SELECT SUM(capacity) as total_capacity, COUNT(DISTINCT country) as project_count FROM wind_farms WHERE country IN ('Germany', 'Spain');

CREATE TABLE donations (id INT, donor_name TEXT, country TEXT, donation_amount DECIMAL, donation_date DATE); INSERT INTO donations (id, donor_name, country, donation_amount, donation_date) VALUES (1, 'Ramesh Kumar', 'India', 25.00, '2019-12-15'); INSERT INTO donations (id, donor_name, country, donation_amount, donation_date) VALUES (2, 'Sita Patel', 'India', 50.00, '2019-07-23');
Q: What is the minimum donation amount made in India in 2019?
A: SELECT MIN(donation_amount) FROM donations WHERE country = 'India' AND YEAR(donation_date) = 2019;

CREATE TABLE Art (id INT, title VARCHAR(255), artist_id INT, gallery_id INT, value INT); CREATE TABLE Gallery (id INT, name VARCHAR(255));
Q: Identify galleries with the highest and lowest average value of artworks on display.
A: SELECT Gallery.name, AVG(Art.value) AS avg_value FROM Gallery JOIN Art ON Gallery.id = Art.gallery_id GROUP BY Gallery.name ORDER BY avg_value DESC LIMIT 1;

CREATE TABLE treatment_facilities (facility_id INT, facility_name VARCHAR(255), state VARCHAR(255), last_inspection_date DATE); INSERT INTO treatment_facilities (facility_id, facility_name, state, last_inspection_date) VALUES (1, 'Plant A', 'Texas', '2021-01-01'), (2, 'Plant B', 'Texas', '2019-08-15'); CREATE TABLE droughts (drought_id INT, facility_id INT, start_date DATE, end_date DATE); INSERT INTO droughts (drought_id, facility_id, start_date, end_date) VALUES (1, 1, '2020-06-01', '2020-08-31'), (2, 2, '2019-07-01', '2019-09-30');
Q: How many water treatment facilities in Texas have been affected by droughts in the last 5 years?
A: SELECT COUNT(DISTINCT f.facility_id) FROM treatment_facilities f INNER JOIN droughts d ON f.facility_id = d.facility_id WHERE f.state = 'Texas' AND d.start_date >= DATE_SUB(f.last_inspection_date, INTERVAL 5 YEAR);

CREATE TABLE IoTDevices (device_id INT, device_type VARCHAR(20), region VARCHAR(10)); INSERT INTO IoTDevices (device_id, device_type, region) VALUES (1, 'Soil Moisture Sensor', 'West'); INSERT INTO IoTDevices (device_id, device_type, region) VALUES (2, 'Light Sensor', 'East'); INSERT INTO IoTDevices (device_id, device_type, region) VALUES (3, 'Temperature Sensor', 'North');
Q: How many IoT devices are active in region 'East'?
A: SELECT COUNT(*) FROM IoTDevices WHERE region = 'East';

CREATE TABLE soil (id INT PRIMARY KEY, type VARCHAR(50), nutrients VARCHAR(50), location VARCHAR(50)); INSERT INTO soil (id, type, nutrients, location) VALUES (1, 'Clay', 'Nitrogen, Phosphorus, Potassium', 'Winterfield');
Q: What is the soil type and nutrients for the farms located in 'Winterfield'?
A: SELECT soil.type, soil.nutrients FROM soil WHERE soil.location = 'Winterfield';

CREATE TABLE ptsd_diagnosis (patient_id INT, age INT, condition VARCHAR(255), country VARCHAR(255)); INSERT INTO ptsd_diagnosis (patient_id, age, condition, country) VALUES (1, 35, 'PTSD', 'Japan'); INSERT INTO ptsd_diagnosis (patient_id, age, condition, country) VALUES (2, 40, 'Anxiety', 'Japan');
Q: What is the maximum age of patients diagnosed with PTSD in Japan?
A: SELECT MAX(age) FROM ptsd_diagnosis WHERE condition = 'PTSD' AND country = 'Japan';

CREATE TABLE company_investments (investment_id INT, company_id INT, company_sector VARCHAR(20), investment_amount FLOAT); INSERT INTO company_investments (investment_id, company_id, company_sector, investment_amount) VALUES (1, 1, 'technology', 150000), (2, 2, 'finance', 200000), (3, 3, 'technology', 120000), (4, 5, 'healthcare', 250000), (5, 6, 'technology', 180000), (6, 7, 'technology', 90000); CREATE TABLE company_ESG_ratings_extended (company_id INT, ESG_rating FLOAT); INSERT INTO company_ESG_ratings_extended (company_id, ESG_rating) VALUES (1, 85.2), (2, 78.1), (3, 88.5), (4, 65.3), (5, 92.7), (6, 81.8), (7, 89.5);
Q: What is the total investment amount in companies that have a high ESG rating (greater than 85) and are in the 'technology' sector?
A: SELECT SUM(investment_amount) FROM company_investments JOIN company_ESG_ratings_extended ON company_investments.company_id = company_ESG_ratings_extended.company_id WHERE company_ESG_ratings_extended.ESG_rating > 85 AND company_investments.company_sector = 'technology';

CREATE TABLE news_reporters (reporter_id INT, name VARCHAR(50), gender VARCHAR(10), age INT, years_of_experience INT); INSERT INTO news_reporters (reporter_id, name, gender, age, years_of_experience) VALUES (1, 'Anna Smith', 'Female', 35, 12), (2, 'Bella Johnson', 'Female', 28, 6), (3, 'Mike Davis', 'Male', 45, 20);
